"use client";

/** Minimal 5-year trend line — no animation, editorial stroke */
export function TrendLine({ data }: { data: number[] }) {
  const w = 64;
  const h = 20;
  const min = Math.min(...data);
  const max = Math.max(...data);
  const range = max - min || 1;
  const pts = data
    .map((v, i) => {
      const x = (i / (data.length - 1)) * w;
      const y = h - ((v - min) / range) * (h - 2) - 1;
      return `${x},${y}`;
    })
    .join(" ");

  return (
    <svg width={w} height={h} aria-hidden>
      <polyline
        fill="none"
        stroke="currentColor"
        strokeWidth="1.25"
        points={pts}
        strokeLinecap="round"
        strokeLinejoin="round"
        className="text-[#9A7B4F]"
      />
    </svg>
  );
}
