"use client";

import React, { useState, useRef, useEffect, useCallback } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { Send, X, Bot } from "lucide-react";
import { MOCK_UNIVERSITIES } from "../../data";

interface Message {
  id: string;
  sender: "user" | "bot";
  text: string;
  timestamp: Date;
}

const BUBBLE_SIZE = 64;
const POS_STORAGE_KEY = "aur_chatbot_position";
const DRAG_THRESHOLD = 8;

function getSafeBounds() {
  if (typeof window === "undefined") {
    return { minX: 12, minY: 72, maxX: 300, maxY: 500 };
  }
  const isMobile = window.innerWidth < 768;
  const margin = 12;
  const topReserve = 72;
  const bottomReserve = isMobile ? 96 : 28;
  return {
    minX: margin,
    minY: topReserve,
    maxX: window.innerWidth - BUBBLE_SIZE - margin,
    maxY: window.innerHeight - BUBBLE_SIZE - bottomReserve,
  };
}

function getDefaultPosition() {
  const { minX, minY, maxX, maxY } = getSafeBounds();
  const isMobile = typeof window !== "undefined" && window.innerWidth < 768;
  const x = isMobile ? minX : maxX;
  const y = maxY;
  return {
    x: Math.min(maxX, Math.max(minX, x)),
    y: Math.min(maxY, Math.max(minY, y)),
  };
}

function clampPosition(pos: { x: number; y: number }) {
  const { minX, minY, maxX, maxY } = getSafeBounds();
  return {
    x: Math.min(maxX, Math.max(minX, pos.x)),
    y: Math.min(maxY, Math.max(minY, pos.y)),
  };
}

export default function Chatbot() {
  const [isOpen, setIsOpen] = useState(false);
  const [messages, setMessages] = useState<Message[]>([
    {
      id: "welcome",
      sender: "bot",
      text: "Hi there! I am your Asia University Rankings AI Assistant. Ask me about rankings, specific universities, countries, tuition fees, or medical programs!",
      timestamp: new Date(),
    },
  ]);
  const [inputVal, setInputVal] = useState("");
  const [isTyping, setIsTyping] = useState(false);
  const [showTooltip, setShowTooltip] = useState(true);
  const [position, setPosition] = useState({ x: 20, y: 400 });
  const [isDragging, setIsDragging] = useState(false);

  const messagesEndRef = useRef<HTMLDivElement>(null);
  const dragStartPos = useRef({ x: 0, y: 0 });
  const pointerStart = useRef({ x: 0, y: 0 });
  const hasMoved = useRef(false);
  const positionRef = useRef(position);

  useEffect(() => {
    positionRef.current = position;
  }, [position]);

  useEffect(() => {
    const saved = localStorage.getItem(POS_STORAGE_KEY);
    if (saved) {
      try {
        const parsed = JSON.parse(saved) as { x: number; y: number };
        setPosition(clampPosition(parsed));
        return;
      } catch {
        /* use default */
      }
    }
    setPosition(getDefaultPosition());
  }, []);

  useEffect(() => {
    const onResize = () => setPosition((p) => clampPosition(p));
    window.addEventListener("resize", onResize);
    return () => window.removeEventListener("resize", onResize);
  }, []);

  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [messages, isTyping]);

  useEffect(() => {
    const timer = setTimeout(() => setShowTooltip(false), 6000);
    return () => clearTimeout(timer);
  }, []);

  const persistPosition = useCallback((pos: { x: number; y: number }) => {
    localStorage.setItem(POS_STORAGE_KEY, JSON.stringify(pos));
  }, []);

  const handlePointerDown = (e: React.PointerEvent<HTMLButtonElement>) => {
    e.currentTarget.setPointerCapture(e.pointerId);
    setIsDragging(true);
    hasMoved.current = false;
    dragStartPos.current = { ...positionRef.current };
    pointerStart.current = { x: e.clientX, y: e.clientY };
  };

  const handlePointerMove = (e: React.PointerEvent<HTMLButtonElement>) => {
    if (!isDragging) return;
    const dx = e.clientX - pointerStart.current.x;
    const dy = e.clientY - pointerStart.current.y;
    if (Math.abs(dx) + Math.abs(dy) > DRAG_THRESHOLD) {
      hasMoved.current = true;
    }
    const next = clampPosition({
      x: dragStartPos.current.x + dx,
      y: dragStartPos.current.y + dy,
    });
    setPosition(next);
  };

  const handlePointerUp = (e: React.PointerEvent<HTMLButtonElement>) => {
    if (e.currentTarget.hasPointerCapture(e.pointerId)) {
      e.currentTarget.releasePointerCapture(e.pointerId);
    }
    setIsDragging(false);
    persistPosition(positionRef.current);
    if (!hasMoved.current) {
      setIsOpen((open) => !open);
      setShowTooltip(false);
    }
  };

  const getBotResponse = (input: string): string => {
    const query = input.toLowerCase().trim();

    if (query.includes("hello") || query.includes("hi") || query.includes("hey")) {
      return "Hello! How can I help you today? You can ask me about regional admissions, tuition rankings, or specific subjects like engineering/medicine.";
    }

    const matchedUnis = MOCK_UNIVERSITIES.filter(
      (uni) =>
        query.includes(uni.name.toLowerCase()) ||
        query.includes(uni.id.toLowerCase()) ||
        (uni.id === "nus" && query.includes("nus")) ||
        (uni.id === "hku" && query.includes("hku")) ||
        (uni.id === "snu" && query.includes("snu")) ||
        (uni.id === "ntu" && query.includes("ntu")) ||
        (uni.id === "kaist" && query.includes("kaist")) ||
        (uni.id === "cuhk" && query.includes("cuhk")) ||
        (uni.id === "iisc" && query.includes("iisc")) ||
        (uni.id === "iit" && query.includes("iit")) ||
        (query.includes("tashkent medical") && uni.id === "tashkent-med")
    );

    if (matchedUnis.length > 0) {
      const uni = matchedUnis[0];
      return `**${uni.name}** (${uni.location})
• **Asia Standing Rank**: #${uni.history[0]}
• **Percentile Score**: ${uni.overall}/100
• **Research Citations Index**: ${uni.citations}/100
• **Annual Tuition**: ${uni.tuition}
• **Popular Subjects**: ${uni.subjects.slice(0, 3).join(", ")}
• **Medicine Program Taught**: ${uni.hasMedicine ? "Yes (English-medium)" : "No"}

*${uni.description}*`;
    }

    if (
      query.includes("medicine") ||
      query.includes("medical") ||
      query.includes("mbbs") ||
      query.includes("md") ||
      query.includes("doctor")
    ) {
      const medUnis = MOCK_UNIVERSITIES.filter((u) => u.hasMedicine);
      return `Here are the top indexed universities offering **Medical / MD / MBBS Programs**:
${medUnis
  .slice(0, 5)
  .map((u) => `• **${u.name}** (Rank #${u.history[0]}, ${u.location}) - Tuition: ${u.tuition}`)
  .join("\n")}
All Central Asian options feature WHO-recognized, English-medium MBBS courses for international students.`;
    }

    if (
      query.includes("uzbekistan") ||
      query.includes("tashkent") ||
      query.includes("samarkand") ||
      query.includes("fergana") ||
      query.includes("bukhara")
    ) {
      const uzUnis = MOCK_UNIVERSITIES.filter((u) => u.location.toLowerCase() === "uzbekistan");
      return `**Uzbekistan Admissions & Universities**:
${uzUnis
  .map((u) => `• **${u.name}** (Rank #${u.history[0]}) - Estimated Tuition: ${u.tuition}`)
  .join("\n")}
These medical schools hosts over 2,000 international scholars and provide intensive clinical anatomy practice.`;
    }

    if (
      query.includes("japan") ||
      query.includes("tokyo") ||
      query.includes("kyoto") ||
      query.includes("osaka") ||
      query.includes("tsukuba")
    ) {
      const jpUnis = MOCK_UNIVERSITIES.filter((u) => u.location.toLowerCase() === "japan");
      return `**Top Research Japanese Universities**:
${jpUnis
  .map((u) => `• **${u.name}** (Rank #${u.history[0]}) - Citations: ${u.citations}/100`)
  .join("\n")}
These public institutions are highly competitive and offer excellent research facilities.`;
    }

    if (query.includes("singapore") || query.includes("nus") || query.includes("ntu")) {
      const sgUnis = MOCK_UNIVERSITIES.filter((u) => u.location.toLowerCase() === "singapore");
      return `**Singapore Global Academic Nodes**:
${sgUnis
  .map(
    (u) =>
      `• **${u.name}** (Rank #${u.history[0]}) - Citation Index: ${u.citations}/100. Tuition is higher (approx. ${u.tuition}), but global merit-based scholarships are available.`
  )
  .join("\n")}`;
    }

    if (
      query.includes("india") ||
      query.includes("iit") ||
      query.includes("iisc") ||
      query.includes("bombay") ||
      query.includes("delhi")
    ) {
      const inUnis = MOCK_UNIVERSITIES.filter((u) => u.location.toLowerCase() === "india");
      return `**Top Indian Institutions**:
${inUnis
  .map(
    (u) =>
      `• **${u.name}** (Rank #${u.history[0]}) - Citations: ${u.citations}/100 (IISc holds the world's highest citations-per-faculty score!)`
  )
  .join("\n")}`;
    }

    if (
      query.includes("tuition") ||
      query.includes("fee") ||
      query.includes("cheap") ||
      query.includes("cost") ||
      query.includes("expensive") ||
      query.includes("price")
    ) {
      const getTuitionVal = (t: string) => {
        const num = parseInt(t.replace(/[^0-9]/g, ""));
        return isNaN(num) ? 99999 : num;
      };
      const sorted = [...MOCK_UNIVERSITIES].sort(
        (a, b) => getTuitionVal(a.tuition) - getTuitionVal(b.tuition)
      );
      return `**Tuition Estimates Q&A**:
*Budget-friendly Medical/Academic Nodes:*
${sorted
  .slice(0, 5)
  .map((u) => `• **${u.name}** (${u.location}) - **${u.tuition}**`)
  .join("\n")}

*High-tier Premium Universities:*
${sorted
  .slice(-3)
  .reverse()
  .map((u) => `• **${u.name}** (${u.location}) - **${u.tuition}**`)
  .join("\n")}`;
    }

    if (query.includes("rank") || query.includes("best") || query.includes("top")) {
      const top5 = MOCK_UNIVERSITIES.slice(0, 5);
      return `Here are the current **Top 5 Asia Universities** based on our audited indexes:
${top5
  .map((u, i) => `${i + 1}. **${u.name}** (Rank #${u.history[0]}, ${u.location}) - Index Score: ${u.overall}`)
  .join("\n")}`;
    }

    if (
      query.includes("score") ||
      query.includes("calculate") ||
      query.includes("weight") ||
      query.includes("formula") ||
      query.includes("metrics")
    ) {
      return `Our **Asia University Rankings Index** evaluates institutions across 5 key weight metrics:
• **Citations Index** (30% weight) - Citation density output
• **Research Output** (30% weight) - Peer-audited publications
• **Employability Rate** (20% weight) - Placements
• **Teaching Environment** (10% weight) - Faculty ratio
• **International Diversity** (10% weight) - Student diversity

You can dynamically adjust these weights in the **Rankings Engine** page!`;
    }

    return "I couldn't find a direct matches in our database. Try asking about: 'medical programs', 'Uzbekistan tuition', 'top 5 universities', or specific names like 'Tsinghua' or 'NUS'!";
  };

  const handleSend = (text: string) => {
    if (!text.trim()) return;

    const userMsg: Message = {
      id: Math.random().toString(),
      sender: "user",
      text,
      timestamp: new Date(),
    };

    setMessages((prev) => [...prev, userMsg]);
    setInputVal("");
    setIsTyping(true);

    setTimeout(() => {
      const replyText = getBotResponse(text);
      const botMsg: Message = {
        id: Math.random().toString(),
        sender: "bot",
        text: replyText,
        timestamp: new Date(),
      };
      setMessages((prev) => [...prev, botMsg]);
      setIsTyping(false);
    }, 800);
  };

  const formatText = (text: string) => {
    return text.split("\n").map((line, i) => {
      const content = line;
      const boldRegex = /\*\*(.*?)\*\*/g;
      const italicRegex = /\*(.*?)\*/g;
      const tempText = content.replace(boldRegex, "<b>$1</b>").replace(italicRegex, "<i>$1</i>");

      return (
        <div
          key={i}
          className="mb-1 leading-relaxed text-xs"
          dangerouslySetInnerHTML={{
            __html: tempText
              .replace(/&/g, "&amp;")
              .replace(/</g, "&lt;")
              .replace(/>/g, "&gt;")
              .replace(/&lt;b&gt;(.*?)&lt;\/b&gt;/g, "<strong>$1</strong>")
              .replace(/&lt;i&gt;(.*?)&lt;\/i&gt;/g, "<em>$1</em>"),
          }}
        />
      );
    });
  };

  return (
    <>
      {/* Floating draggable bubble — one touch to drag; tap (no drag) toggles chat */}
      <button
        type="button"
        aria-label={isOpen ? "Close assistant" : "Open assistant — drag to move"}
        onPointerDown={handlePointerDown}
        onPointerMove={handlePointerMove}
        onPointerUp={handlePointerUp}
        onPointerCancel={handlePointerUp}
        style={{
          left: position.x,
          top: position.y,
          width: BUBBLE_SIZE,
          height: BUBBLE_SIZE,
          touchAction: "none",
        }}
        className={`fixed z-[55] rounded-full select-none transition-shadow duration-200 ${
          isDragging ? "cursor-grabbing scale-105 shadow-2xl" : "cursor-grab"
        }`}
      >
        <div className="relative w-full h-full">
          <div
            className={`w-full h-full rounded-full flex items-center justify-center border shadow-md transition-colors ${
              isOpen
                ? "bg-[#141820] border-[#9A7B4F] text-[#F6F3EE]"
                : "bg-[#141820] border-[#DDD8CF] text-[#C4A574] hover:border-[#9A7B4F]"
            }`}
          >
            {isOpen ? (
              <X className="h-6 w-6" />
            ) : (
              <Bot className="h-7 w-7" />
            )}
          </div>
        </div>

        <AnimatePresence>
          {showTooltip && !isOpen && !isDragging && (
            <motion.span
              initial={{ opacity: 0, y: 4 }}
              animate={{ opacity: 1, y: 0 }}
              exit={{ opacity: 0 }}
              className="absolute left-full ml-3 top-1/2 -translate-y-1/2 w-36 hidden sm:block bg-[#141820] text-[#F6F3EE] text-[10px] font-medium tracking-wide px-3 py-2 shadow-lg pointer-events-none"
            >
              Drag anywhere · Tap to chat
            </motion.span>
          )}
        </AnimatePresence>
      </button>

      <AnimatePresence>
        {isOpen && (
          <div className="fixed inset-0 z-[54] pointer-events-none flex items-end justify-center sm:items-end sm:justify-end p-4 sm:p-6 md:p-8">
            <motion.div
              initial={{ opacity: 0, y: 40, scale: 0.96 }}
              animate={{ opacity: 1, y: 0, scale: 1 }}
              exit={{ opacity: 0, y: 24, scale: 0.96 }}
              transition={{ duration: 0.22, ease: "easeOut" }}
              className="pointer-events-auto w-full max-w-sm sm:max-w-md h-[min(480px,calc(100vh-120px))] bg-white border border-slate-200 rounded-2xl shadow-2xl flex flex-col overflow-hidden mb-20 md:mb-6"
            >
              <div className="p-4 border-b border-slate-100 bg-[#FAFAFA] flex items-center justify-between shrink-0">
                <div className="flex items-center gap-2.5">
                  <div className="w-9 h-9 rounded-full bg-[#0B1020] flex items-center justify-center text-[#F97316]">
                    <Bot className="h-5 w-5" />
                  </div>
                  <div>
                    <h3 className="font-[family-name:var(--font-display)] text-sm font-bold text-[#111827]">
                      AUR Intelligence Assistant
                    </h3>
                    <span className="text-[9px] uppercase tracking-widest text-[#6B7280] font-semibold">
                      Institutional index mode
                    </span>
                  </div>
                </div>
                <button
                  type="button"
                  onClick={() => setIsOpen(false)}
                  aria-label="Close chat"
                  className="p-2 rounded-lg text-[#6B7280] hover:bg-slate-100 hover:text-[#111827] transition-colors"
                >
                  <X className="h-5 w-5" />
                </button>
              </div>

              <div className="flex-1 overflow-y-auto p-4 space-y-4">
                {messages.map((msg) => {
                  const isBot = msg.sender === "bot";
                  return (
                    <div
                      key={msg.id}
                      className={`flex ${isBot ? "justify-start" : "justify-end"} items-start gap-2`}
                    >
                      {isBot && (
                        <div className="w-7 h-7 rounded-full bg-[#FAFAFA] border border-slate-200 flex items-center justify-center shrink-0 text-[#F97316]">
                          <Bot className="h-4 w-4" />
                        </div>
                      )}
                      <div
                        className={`max-w-[82%] rounded-2xl px-3.5 py-2.5 text-xs ${
                          isBot
                            ? "bg-[#FAFAFA] text-[#111827] border border-slate-100 rounded-tl-sm"
                            : "bg-[#0B1020] text-white rounded-tr-sm"
                        }`}
                      >
                        {isBot ? formatText(msg.text) : <div>{msg.text}</div>}
                      </div>
                    </div>
                  );
                })}

                {isTyping && (
                  <div className="flex justify-start items-center gap-2">
                    <div className="w-7 h-7 rounded-full bg-[#FAFAFA] border border-slate-200 flex items-center justify-center shrink-0">
                      <Bot className="h-4 w-4 text-[#F97316]" />
                    </div>
                    <div className="bg-[#FAFAFA] border border-slate-100 rounded-2xl px-4 py-3 flex gap-1">
                      <div className="w-1.5 h-1.5 rounded-full bg-[#6B7280] animate-bounce" />
                      <div className="w-1.5 h-1.5 rounded-full bg-[#6B7280] animate-bounce [animation-delay:150ms]" />
                      <div className="w-1.5 h-1.5 rounded-full bg-[#6B7280] animate-bounce [animation-delay:300ms]" />
                    </div>
                  </div>
                )}
                <div ref={messagesEndRef} />
              </div>

              <div className="px-4 py-2 flex flex-wrap gap-1.5 border-t border-slate-100 bg-[#FAFAFA] shrink-0">
                {["Top 5 Universities", "MBBS in Uzbekistan", "NUS vs NTU", "Weight formula"].map(
                  (chip) => (
                    <button
                      key={chip}
                      type="button"
                      onClick={() => handleSend(chip)}
                      className="text-[9px] font-bold uppercase tracking-wider px-2.5 py-1 border border-slate-200 bg-white hover:border-[#0B1020] text-[#6B7280] hover:text-[#111827] rounded-full transition-colors"
                    >
                      {chip}
                    </button>
                  )
                )}
              </div>

              <form
                onSubmit={(e) => {
                  e.preventDefault();
                  handleSend(inputVal);
                }}
                className="p-3 border-t border-slate-100 bg-white flex items-center gap-2 shrink-0"
              >
                <input
                  type="text"
                  value={inputVal}
                  onChange={(e) => setInputVal(e.target.value)}
                  placeholder="Ask rankings assistant..."
                  className="flex-grow bg-[#FAFAFA] border border-slate-200 rounded-xl px-3.5 py-2.5 text-xs focus:outline-none focus:border-[#2563EB] text-[#111827]"
                />
                <button
                  type="submit"
                  disabled={!inputVal.trim()}
                  className="p-2.5 bg-[#0B1020] hover:bg-[#111827] text-white disabled:opacity-40 rounded-xl transition-colors"
                >
                  <Send className="h-4 w-4" />
                </button>
              </form>
            </motion.div>
          </div>
        )}
      </AnimatePresence>
    </>
  );
}
